SELECT COUNT(*) AS days_above_30
FROM seattle_weather
WHERE temp_max > 30;

SELECT
  100.0 * SUM(CASE WHEN payment_type = 'credit_card' THEN 1 ELSE 0 END) / COUNT(*) AS pct_credit_card
FROM olist_order_payments;

SELECT 100.0 * SUM(CASE WHEN order_status = 'canceled' THEN 1 ELSE 0 END) / COUNT(*) AS canceled_percentage
FROM olist_orders
WHERE order_status IS NOT NULL;
